"use strict";exports.id=7077,exports.ids=[7077],exports.modules={37077:(e,t,i)=>{i.r(t),i.d(t,{typescriptResourceData:()=>r});let r={sections:[{id:"official-docs",title:"Official Documentation",description:"Primary references maintained by standard bodies and the TypeScript core team.",icon:"BookOpen",resources:[{title:"TypeScript Handbook",url:"https://www.typescriptlang.org/docs/handbook/intro.html",description:"The definitive guide to TypeScript. Explains basic types, generics, interfaces, classes, and compiler configuration.",type:"free",difficulty:"Beginner",badge:"Official",author:"Microsoft"},{title:"TypeScript TSConfig Reference",url:"https://www.typescriptlang.org/tsconfig",description:"A detailed catalog of every single compiler flag and property available in tsconfig.json.",type:"free",difficulty:"Intermediate",badge:"Official"}]},{id:"books",title:"Books",description:"Must-read titles that stand the test of time for TypeScript mastery.",icon:"Library",resources:[{title:"Effective TypeScript",url:"https://effectivetypescript.com/",description:"62 specific ways to improve your TypeScript. Essential for learning how to design types and work with the compiler.",type:"paid",difficulty:"Intermediate",badge:"Must Read",author:"Dan Vanderkam",estimatedHours:25},{title:"Programming TypeScript",url:"https://www.oreilly.com/library/view/programming-typescript/9781492037644/",description:"A detailed manual on how to design type-safe systems and compile backend and frontend TypeScript applications.",type:"paid",difficulty:"Advanced",author:"Boris Cherny",estimatedHours:35}]},{id:"video-courses",title:"Video Courses",description:"Structured video learning paths from beginner to expert level.",icon:"PlayCircle",resources:[{title:"Total TypeScript",url:"https://www.totaltypescript.com/",description:"The ultimate TypeScript masterclass. Focuses on advanced TypeScript concepts, type wizardry, and library development.",type:"paid",difficulty:"Advanced",badge:"Best Rated",author:"Matt Pocock",estimatedHours:30},{title:"TypeScript Course for Beginners — freeCodeCamp",url:"https://www.youtube.com/watch?v=zQnBQ4tB3ZA",description:"A full video course introducing TypeScript to JavaScript developers.",type:"free",difficulty:"Beginner",badge:"Free",author:"freeCodeCamp",estimatedHours:5}]},{id:"practice",title:"Practice Platforms",description:"Sharpen your TypeScript with coding challenges and exercises.",icon:"Code2",resources:[{title:"Type Hero",url:"https://typehero.dev/",description:"Connect, collaborate, and grow your TypeScript skills with interactive coding challenges.",type:"free",difficulty:"Intermediate",badge:"Community Pick"},{title:"TypeScript Type Challenges",url:"https://github.com/type-challenges/type-challenges",description:"A collection of hundreds of online challenges ranging from warm-up to extreme difficulties.",type:"free",difficulty:"Advanced",badge:"Best Rated"}]},{id:"github",title:"GitHub Repositories",description:"Open-source projects and curated lists worth starring.",icon:"Github",resources:[{title:"Awesome TypeScript",url:"https://github.com/dzharii/awesome-typescript",description:"A curated list of awesome TypeScript frameworks, libraries, tools, and guides.",type:"free",difficulty:"Beginner",badge:"Community Pick"}]},{id:"tools",title:"Developer Tools",description:"Essential tools for productive TypeScript development.",icon:"Wrench",resources:[{title:"TypeScript Playground",url:"https://www.typescriptlang.org/play",description:"An online environment to write, share, and inspect the transpiled JavaScript of your TS code.",type:"free",difficulty:"Beginner",badge:"Official"},{title:"TS-Node",url:"https://typestrong.org/ts-node/",description:"TypeScript execution engine and REPL for Node.js. Run TS files directly without ahead-of-time compilation.",type:"free",difficulty:"Beginner"}]},{id:"community",title:"Community & Forums",description:"Active communities to ask questions and stay current.",icon:"Users",resources:[{title:"r/typescript",url:"https://www.reddit.com/r/typescript/",description:"The main Reddit forum for TypeScript tips, questions, and releases.",type:"free",difficulty:"Beginner"}]}],learningPath:{totalWeeks:6,totalHours:75,level:"Beginner",description:"A structured 6-week program to master TypeScript, transitioning from basic types and compilers to complex generic modeling.",weeks:[{week:1,title:"Introduction & Compiler Setup",description:"Install TypeScript, configure tsconfig.json, and understand primitive types and basic type annotation.",topics:["Installing TS & TS-Node","Creating & Config TSConfig.json","Primitive types: number, string, boolean","Any, Unknown, Void, and Never","Type Assertions & Casts"],estimatedHours:10,milestoneProject:"Configure a clean TS build environment and create basic typed variables"},{week:2,title:"Interfaces, Types & Objects",description:"Understand interfaces vs type aliases, object typing, optional properties, and readonly parameters.",topics:["Type Aliases vs Interfaces","Optional Properties & Readonly Fields","Extending Interfaces vs Intersections","Index Signatures","Tuple Types"],estimatedHours:12,milestoneProject:"Design the interface for a complex shopping cart system"},{week:3,title:"Functions, Enums & Literal Types",description:"Type functions, write function overloads, structure data with Enums, and use literal types.",topics:["Function signatures & Optionals","Function Overloading","Enums: Numeric, String, and Const Enums","Literal Types (String/Number Literals)","Discriminated Unions"],estimatedHours:12,milestoneProject:"Build a calculator function utilizing literal type operators and overloads"},{week:4,title:"Classes & Generics Foundations",description:"Work with object-oriented TypeScript classes, access modifiers, and basic generics.",topics:["Public, Private, Protected, and Readonly","Abstract Classes & Implementing Interfaces","Generic Functions & Type Parameters","Generic Interfaces","Type Constraints (extends)"],estimatedHours:14,milestoneProject:"Build a generic DataRepository class to fetch and save database objects"},{week:5,title:"Advanced Types & Utility Types",description:"Learn conditional types, keyof, typeof, mapped types, and standard utility types like Pick, Omit, and Partial.",topics:["keyof and typeof operators","Utility Types: Partial, Required, Readonly","Utility Types: Pick, Omit, Record","Conditional Types basics","Template Literal Types"],estimatedHours:14,milestoneProject:"Create a custom state transformer using mapped and utility types"},{week:6,title:"Type Narrowing & Compiler Rules",description:"Master strict null checks, type guards, assertion functions, and compiler safety settings.",topics:["typeof, instanceof, and in Type Guards","Custom User-Defined Type Guards","Strict Null Checks & Optional Chaining","Configuring strict: true in TSConfig","Declaration Files (.d.ts)"],estimatedHours:13,milestoneProject:"Build a type-safe parser for API responses with full type validation"}]},skillTree:[{id:"ts-basics",name:"Types & Setup",description:"Understanding type declarations, interfaces, and compiler setups.",level:"category",children:[{id:"ts-typealias",name:"Types vs Interfaces",description:"Understanding when to use type aliases versus interfaces for structure typing.",level:"topic",codeExample:`// Interface - extendable and declaration mergeable
interface User {
  id: string;
  name: string;
}
interface User {
  role: string; // Merged!
}

// Type Alias - perfect for unions, intersections, primitives
type ID = string | number;
type AdminUser = User & { permissions: string[] };`},{id:"ts-union",name:"Discriminated Unions",description:"Using a literal tag to safely narrow unions of objects.",level:"topic",codeExample:`interface Success {
  status: 'success';
  data: string[];
}
interface Failure {
  status: 'failed';
  error: Error;
}
type ApiResponse = Success | Failure;

function handle(response: ApiResponse) {
  if (response.status === 'success') {
    console.log(response.data); // Narrowed to Success
  } else {
    console.error(response.error); // Narrowed to Failure
  }
}`}]},{id:"ts-advanced",name:"Advanced Types",description:"Generics, utility types, and advanced compiler transformations.",level:"category",children:[{id:"ts-generics",name:"Generics & Constraints",description:"Writing reusable components and structures that work with a variety of types.",level:"topic",codeExample:`// Generic function with constraint
function getLength<T extends { length: number }>(item: T): number {
  return item.length;
}

getLength('hello'); // valid
getLength([1, 2]);  // valid
// getLength(10);   // error: number does not have length`},{id:"ts-utilities",name:"Utility Types",description:"Transforming existing types into variations with Pick, Omit, and Partial.",level:"topic",codeExample:`interface Article {
  id: string;
  title: string;
  body: string;
  published: boolean;
}

// Partial - all fields optional
type UpdateArticleDto = Partial<Article>;

// Omit - remove fields
type NewArticleDto = Omit<Article, 'id'>;

// Pick - extract select fields
type ShortArticle = Pick<Article, 'id' | 'title'>;`}]}],aiQA:[{keywords:["interface","type","difference"],question:"What is the difference between an Interface and a Type Alias in TypeScript?",answer:"Interfaces can be extended via inheritance (`extends`) and support declaration merging (defining the same interface name twice merges their fields). Type aliases cannot be merged and can represent unions (`string | number`), tuples, intersection types, and primitives. Use interfaces for public APIs or object shapes, and types for complex models, union types, or function shapes."},{keywords:["any","unknown","never"],question:"What is the difference between any, unknown, and never?",answer:"`any` disables all type-checking and allows any operation. `unknown` is the type-safe counterpart to `any`: you can assign anything to it, but you cannot perform operations on it until you narrow its type (via `typeof`, `instanceof`, etc.). `never` represents values that can never occur, such as a function that always throws an error or an impossible branch in a type switch."},{keywords:["type guard","narrowing"],question:"What is a User-Defined Type Guard and how do you write one?",answer:"A User-Defined Type Guard is a function that returns a type predicate (`parameterName is Type`). It allows you to write custom check functions that narrow a union type inside conditional blocks. Example: `function isFish(pet: Fish | Bird): pet is Fish { return (pet as Fish).swim !== undefined; }`."}]}}};